// src/Login.js
import React, { useState } from "react";

const apiBase = "https://prasa-backend-1.onrender.com";

function Login({ onLoginSuccess }) {
  const [empld, setEmpld] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const handleLogin = async (e) => {
    e.preventDefault();
    setError("");

    if (!empld || !password) {
      setError("Please enter Employee ID and Password.");
      return;
    }

    try {
      setLoading(true);
      const response = await fetch(`${apiBase}/login`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ empld, password }),
      });

      const data = await response.json();

      if (!response.ok || !data.success) {
        setError(data.message || "Invalid credentials");
      } else {
        onLoginSuccess(data.employee);
      }
    } catch (err) {
      console.error("Login Error:", err);
      setError("Server error. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div
      style={{
        minHeight: "100vh",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        background: "linear-gradient(135deg, #0f9d58 0%, #e8f5e9 60%, #ffffff 100%)",
        padding: 16,
      }}
    >
      <div
        style={{
          width: "100%",
          maxWidth: 380,
          backgroundColor: "#ffffff",
          borderRadius: 20,
          boxShadow: "0 10px 30px rgba(0,0,0,0.15)",
          padding: 24,
          textAlign: "center",
        }}
      >
        {/* Center Logo Box */}
        <div
          style={{
            backgroundColor: "#e8f5e9",
            borderRadius: 16,
            padding: 16,
            display: "flex",
            flexDirection: "column",
            alignItems: "center",
            marginBottom: 16,
          }}
        >
          <img
            src="/logo.png"
            alt="PRASA Logo"
            style={{
              width: 90,
              height: 90,
              objectFit: "contain",
              backgroundColor: "#ffffff",
              borderRadius: 18,
              padding: 10,
              boxShadow: "0 4px 12px rgba(0,0,0,0.08)",
            }}
          />
          <div
            style={{
              marginTop: 10,
              fontSize: 16,
              fontWeight: 600,
              color: "#0f9d58",
            }}
          >
            PRASA Employee Portal
          </div>
        </div>

        <h2
          style={{
            marginBottom: 4,
            color: "#1b5e20",
            fontSize: 20,
            fontWeight: 700,
          }}
        >
          Login
        </h2>
        <p style={{ color: "#4e5d52", fontSize: 13, marginBottom: 16 }}>
          Enter your Employee ID (EMPID) and password to continue.
        </p>

        <form
          onSubmit={handleLogin}
          style={{
            display: "flex",
            flexDirection: "column",
            gap: 10,
            textAlign: "left",
          }}
        >
          <label style={{ fontSize: 13, color: "#2e7d32" }}>EMPID</label>
          <input
            type="text"
            placeholder="Enter Employee ID"
            value={empld}
            onChange={(e) => setEmpld(e.target.value)}
            style={{
              padding: 10,
              borderRadius: 10,
              border: "1px solid #c8e6c9",
              fontSize: 14,
              outline: "none",
            }}
          />

          <label style={{ fontSize: 13, color: "#2e7d32", marginTop: 4 }}>
            Password
          </label>
          <input
            type="password"
            placeholder="Enter Password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            style={{
              padding: 10,
              borderRadius: 10,
              border: "1px solid #c8e6c9",
              fontSize: 14,
              outline: "none",
            }}
          />

          <button
            type="submit"
            disabled={loading}
            style={{
              marginTop: 14,
              backgroundColor: "#0f9d58",
              color: "#ffffff",
              border: "none",
              padding: 12,
              borderRadius: 12,
              cursor: "pointer",
              fontSize: 15,
              fontWeight: 600,
              width: "100%",
            }}
          >
            {loading ? "Logging in..." : "Login"}
          </button>
        </form>

        {error && (
          <p style={{ color: "red", marginTop: 10, fontSize: 13 }}>{error}</p>
        )}
      </div>
    </div>
  );
}

export default Login;
